async (params, browser) => {
  // Open coin page
  await browser.open(`https://coinmarketcap.com/currencies/${params.coin_slug}/`)

  // Wait for coin page to load
  await browser.waitForSelector('h1, h2, [data-role=\'coin-name\']', 15000)

  // Let page data render
  await browser.wait(2500)

  // Scroll for more content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract coin details
  const coin_data = await browser.evaluate(`var h1 = document.querySelector('h1'); var nameEl = document.querySelector('[data-role="coin-name"]') || (h1 ? h1.querySelector('span') : null) || h1; var symbolEl = document.querySelector('[data-role="coin-symbol"]') || (h1 ? h1.querySelector('small') : null); var priceEl = document.querySelector('[data-test="text-cdp-price-display"]'); if (!priceEl) { var spans = document.querySelectorAll('span'); for (var si = 0; si < spans.length; si++) { var txt = spans[si].textContent.trim(); if (/^\$[\d,.]+/.test(txt) && spans[si].closest('h1, h2, [data-test]')) { priceEl = spans[si]; break; } } } var statsData = {}; var dlDivs = document.querySelectorAll('dl div, dt'); dlDivs.forEach(function(item) { var dt = item.tagName === 'DT' ? item : item.querySelector('dt'); var dd = item.tagName === 'DT' ? item.nextElementSibling : item.querySelector('dd'); if (dt && dd) { var key = dt.textContent.trim().toLowerCase().replace(/[^a-z0-9]/g, '_'); statsData[key] = dd.textContent.trim(); } }); var bodyText = document.body.innerText; var mcMatch = bodyText.match(/Market [Cc]ap[^$]*?(\$[\d,.]+[BMTK]?)/); var volMatch = bodyText.match(/Volume \(24h\)[^$]*?(\$[\d,.]+[BMTK]?)/); var supMatch = bodyText.match(/Circulating Supply[^\d]*([\d,.]+\s*[A-Z]*)/); var rankMatch = bodyText.match(/Rank\s*#?(\d+)/i); var descEl = null; var sections = document.querySelectorAll('section, div[id]'); for (var di = 0; di < sections.length; di++) { var heading = sections[di].querySelector('h2, h3'); if (heading && /about|description|what is/i.test(heading.textContent)) { descEl = sections[di].querySelector('p'); break; } } if (!descEl) descEl = document.querySelector('[data-test="coin-description"] p'); var description = descEl ? descEl.textContent.trim().substring(0, 1000) : ''; var tagEls = document.querySelectorAll('a[href*="/view/"]'); var tags = []; tagEls.forEach(function(el) { var t = el.textContent.trim(); if (t && t.length < 50) tags.push(t); }); var linkSection = document.querySelector('div[data-role="links"]') || document.querySelector('section'); var officialLinks = []; if (linkSection) { var allLinks = linkSection.querySelectorAll('a[href^="http"]'); allLinks.forEach(function(el) { if (el.href && !el.href.includes('coinmarketcap.com')) { officialLinks.push({ text: el.textContent.trim(), url: el.href }); } }); } return { name: nameEl ? nameEl.textContent.trim() : '' + params.coin_slug + '', symbol: symbolEl ? symbolEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', rank: rankMatch ? '#' + rankMatch[1] : '', market_cap: mcMatch ? mcMatch[1] : (statsData.market_cap || ''), volume_24h: volMatch ? volMatch[1] : (statsData.volume_24h || ''), circulating_supply: supMatch ? supMatch[1] : (statsData.circulating_supply || ''), stats: statsData, description: description, tags: tags.slice(0, 10), links: officialLinks.slice(0, 10), url: window.location.href }`)

  return coin_data
}
